#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MOD 1000000007

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int count_coprime_subsets(int* arr, int n, int l, int r, int k) {
    int count = 0;
    for (int i = l; i <= r; i++) {
        for (int j = i + 1; j <= r; j++) {
            if (k == 2) {
                if (gcd(arr[i], arr[j]) == 1) count++;
            } else {
                // recursive call for k > 2
            }
        }
    }
    return count;
}

int main() {
    int n;
    scanf("%d", &n);
    int* arr = (int*) malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) scanf("%d", &arr[i]);
    int q;
    scanf("%d", &q);
    for (int i = 0; i < q; i++) {
        int l, r, k;
        scanf("%d %d %d", &l, &r, &k);
        int count = count_coprime_subsets(arr, n, l - 1, r - 1, k);
        printf("%d\n", count % MOD);
    }
    return 0;
}

